void jacobi_kernel(int tsteps, int n, double *A, double *B)
{
    int t, i, j;
    for (t = 0; t < tsteps; t++) {
        #pragma omp parallel for default(shared) private(i, j)
        for (i = 1; i < n - 1; i++) {
            #pragma omp simd
            for (j = 1; j < n - 1; j++) {
                B[i * n + j] = 0.2 * (A[i * n + j] + A[i * n + j - 1] + A[i * n + j + 1] + A[(i + 1) * n + j] + A[(i - 1) * n + j]);
            }
        }
        #pragma omp parallel for default(shared) private(i, j)
        for (i = 1; i < n - 1; i++) {
            #pragma omp simd
            for (j = 1; j < n - 1; j++) {
                A[i * n + j] = 0.2 * (B[i * n + j] + B[i * n + j - 1] + B[i * n + j + 1] + B[(i + 1) * n + j] + B[(i - 1) * n + j]);
            }
        }
    }
}

// 将外层循环分解为 Block_i 和 Block_j，以确保工作集拟合在 L2/L3 缓存中
#define BLOCK_I 64
#define BLOCK_J 64
